页眉与页脚iText5中并没有之前版本HeaderFooter对象设置页眉和页脚，可以利用PdfPageEventHelper来完成页眉页脚的设置工作。PdfPageEventHelper中包含以下事件处理器。
onOpenDocument() — 当打开一个文档时触发，可以用于初始化文档的全局变量。onStartPage() — 当一个页面初始化时触发，可用于初始化页面的设置参数，但是注意这个函数触发时，该页面并没有创建好，不用利用这个函数添加内容，最好利用onEndPage()处理页面的初始化。onEndPage() — 在创建一个新页面完成但写入内容之前触发，是添加页眉、页脚、水印等最佳时机。onCloseDocument() — 在文档关闭之前触发，可以用于释放一些资源。onCloseDocument() — 在文档关闭之前触发，可以用于释放一些资源。

要想出发事件需要在程序中添加事件
如下
PdfReportM1HeaderFooter footer=new PdfReportM1HeaderFooter();writer.setPageEvent(footer);

该类PdfReportM1HeaderFooter继承自PdfPageEventHelper所以可以直接添加、
package demo;/** * Project Name:report * File Name:PdfReportM1HeaderFooter.java * Package Name:com.riambsoft.report.pdf * Date:2013-9-16上午08:59:00 * Copyright (c) 2013, riambsoft All Rights Reserved. * */import java.io.IOException;import com.itextpdf.text.Document;import com.itextpdf.text.DocumentException;import com.itextpdf.text.Element;import com.itextpdf.text.Font;import com.itextpdf.text.PageSize;import com.itextpdf.text.Phrase;import com.itextpdf.text.Rectangle;import com.itextpdf.text.pdf.BaseFont;import com.itextpdf.text.pdf.ColumnText;import com.itextpdf.text.pdf.PdfContentByte;import com.itextpdf.text.pdf.PdfPageEventHelper;import com.itextpdf.text.pdf.PdfTemplate;import com.itextpdf.text.pdf.PdfWriter;/** * ClassName:PdfReportM1HeaderFooter &lt;br/&gt; * Function: TODO ADD FUNCTION. &lt;br/&gt; * Reason: TODO ADD REASON. &lt;br/&gt; * Date: 2013-9-13 上午08:59:00 &lt;br/&gt; * * @author 落雨 * @version 394263788(QQ) * @since JDK 1.5 * @see http://hi.baidu.com/ae6623 */public class PdfReportM1HeaderFooter extends PdfPageEventHelper &#123;    /**     * 页眉     */    public String header = &quot;&quot;;    /**     * 文档字体大小，页脚页眉最好和文本大小一致     */    public int presentFontSize = 12;    /**     * 文档页面大小，最好前面传入，否则默认为A4纸张     */    public Rectangle pageSize = PageSize.A4;    // 模板    public PdfTemplate total;    // 基础字体对象    public BaseFont bf = null;    // 利用基础字体生成的字体对象，一般用于生成中文文字    public Font fontDetail = null;    /**     *     * Creates a new instance of PdfReportM1HeaderFooter 无参构造方法.     *     */    public PdfReportM1HeaderFooter() &#123;    &#125;    /**     *     * Creates a new instance of PdfReportM1HeaderFooter 构造方法.     *     * @param yeMei           页眉字符串     * @param presentFontSize 数据体字体大小     * @param pageSize        页面文档大小，A4，A5，A6横转翻转等Rectangle对象     */    public PdfReportM1HeaderFooter(String yeMei, int presentFontSize, Rectangle pageSize) &#123;        this.header = yeMei;        this.presentFontSize = presentFontSize;        this.pageSize = pageSize;    &#125;    public void setHeader(String header) &#123;        this.header = header;    &#125;    public void setPresentFontSize(int presentFontSize) &#123;        this.presentFontSize = presentFontSize;    &#125;    /**     *     * TODO 文档打开时创建模板     *     * @see com.itextpdf.text.pdf.PdfPageEventHelper#onOpenDocument(com.itextpdf.text.pdf.PdfWriter,     *      com.itextpdf.text.Document)     */    public void onOpenDocument(PdfWriter writer, Document document) &#123;        total = writer.getDirectContent().createTemplate(50, 50);// 共 页 的矩形的长宽高    &#125;    /**     *     * TODO 关闭每页的时候，写入页眉，写入&#x27;第几页共&#x27;这几个字。     *     * @see com.itextpdf.text.pdf.PdfPageEventHelper#onEndPage(com.itextpdf.text.pdf.PdfWriter,     *      com.itextpdf.text.Document)     */    public void onEndPage(PdfWriter writer, Document document) &#123;        try &#123;            if (bf == null) &#123;                bf = BaseFont.createFont(&quot;STSong-Light&quot;, &quot;UniGB-UCS2-H&quot;, false);            &#125;            if (fontDetail == null) &#123;                fontDetail = new Font(bf, presentFontSize, Font.NORMAL);// 数据体字体            &#125;        &#125; catch (DocumentException e) &#123;            e.printStackTrace();        &#125; catch (IOException e) &#123;            e.printStackTrace();        &#125;        // 1.写入页眉        ColumnText.showTextAligned(writer.getDirectContent(), Element.ALIGN_LEFT, new Phrase(header, fontDetail),                document.left(), document.top() + 20, 0);        // 2.写入前半部分的 第 X页/共        int pageS = writer.getPageNumber();        String foot1 = &quot;第 &quot; + pageS + &quot; 页 /共&quot;;        Phrase footer = new Phrase(foot1, fontDetail);        // 3.计算前半部分的foot1的长度，后面好定位最后一部分的&#x27;Y页&#x27;这俩字的x轴坐标，字体长度也要计算进去 = len        float len = bf.getWidthPoint(foot1, presentFontSize);        // 4.拿到当前的PdfContentByte        PdfContentByte cb = writer.getDirectContent();        // 自己增加的        if (pageS == 1) &#123;            Phrase footerLeft = new Phrase(&quot;978-1-4799-0530-031.00 ©2013 IEEE&quot;, fontDetail);            ColumnText.showTextAligned(cb, Element.ALIGN_LEFT, footerLeft, document.left(), document.bottom() - 20, 0);        &#125;        // 5.写入页脚1，x轴就是(右margin+左margin + right() -left()- len)/2.0F        // 再给偏移20F适合人类视觉感受，否则肉眼看上去就太偏左了        // ,y轴就是底边界-20,否则就贴边重叠到数据体里了就不是页脚了；注意Y轴是从下往上累加的，最上方的Top值是大于Bottom好几百开外的。        ColumnText.showTextAligned(cb, Element.ALIGN_CENTER, footer,                (document.rightMargin() + document.right() + document.leftMargin() - document.left() - len) / 2.0F                        + 20F,                document.bottom() - 20, 0);        // 6.写入页脚2的模板（就是页脚的Y页这俩字）添加到文档中，计算模板的和Y轴,X=(右边界-左边界 - 前半部分的len值)/2.0F + len ， y        // 轴和之前的保持一致，底边界-20        cb.addTemplate(total,                (document.rightMargin() + document.right() + document.leftMargin() - document.left()) / 2.0F + 20F,                document.bottom() - 20); // 调节模版显示的位置    &#125;    /**     *     * TODO 关闭文档时，替换模板，完成整个页眉页脚组件     *     * @see com.itextpdf.text.pdf.PdfPageEventHelper#onCloseDocument(com.itextpdf.text.pdf.PdfWriter,     *      com.itextpdf.text.Document)     */    public void onCloseDocument(PdfWriter writer, Document document) &#123;        // 7.最后一步了，就是关闭文档的时候，将模板替换成实际的 Y 值,至此，page x of y 制作完毕，完美兼容各种文档size。        total.beginText();        total.setFontAndSize(bf, presentFontSize);// 生成的模版的字体、颜色        String foot2 = &quot; &quot; + (writer.getPageNumber() - 1) + &quot; 页&quot;;        total.showText(foot2);// 模版显示的内容        total.endText();        total.closePath();    &#125;&#125;



